class MetricsCollector:
    """Lightweight metrics collector for monitoring throughput."""

    def __init__(self):
        self._total_requests = 0
        self._total_messages_received = 0
        self._total_messages_sent = 0
        self._total_bytes_received = 0
        self._total_bytes_sent = 0
        self._start_time = time.time()
        self._errors = 0

    def record_request(self):
        self._total_requests += 1

    def record_message_received(self, size_bytes=0):
        self._total_messages_received += 1
        self._total_bytes_received += size_bytes

    def record_message_sent(self, size_bytes=0):
        self._total_messages_sent += 1
        self._total_bytes_sent += size_bytes

    def record_error(self):
        self._errors += 1

    @property
    def total_requests(self):
        return self._total_requests

    @property
    def uptime(self):
        return int(time.time() - self._start_time)

    def get_stats(self):
        elapsed = time.time() - self._start_time
        return {
            "total_requests": self._total_requests,
            "total_messages_received": self._total_messages_received,
            "total_messages_sent": self._total_messages_sent,
            "total_bytes_received": self._total_bytes_received,
            "total_bytes_sent": self._total_bytes_sent,
            "errors": self._errors,
            "uptime_seconds": elapsed,
            "avg_requests_per_second": self._total_requests / max(elapsed, 1),
        }


class DataProcessor:
    """Core data processing engine. Replace with actual business logic."""

    @staticmethod
    def process(payload: bytes, data_type: str, metadata: dict) -> bytes:
        """Process a single data payload. This is where real processing logic goes."""
        if data_type == "transform":
            return payload[::-1]
        elif data_type == "compress":
            import zlib
            return zlib.compress(payload)
        elif data_type == "decompress":
            import zlib
            return zlib.decompress(payload)
        elif data_type == "hash":
            import hashlib
            return hashlib.sha256(payload).hexdigest().encode()
        elif data_type == "echo":
            return payload
        else:
            # Default: pass through with timestamp
            return payload


class DataStreamServicer(datastream_pb2_grpc.DataStreamServiceServicer):
    """High-performance gRPC servicer for data stream processing."""

