    def ProcessData(self, request, context):
        """Unary RPC - process a single data request."""
        start = time.perf_counter_ns()
        self.metrics.record_request()
        self.metrics.record_message_received(len(request.payload))

        try:
            result = self.processor.process(
                request.payload,
                request.data_type,
                dict(request.metadata)
            )
            elapsed_ns = time.perf_counter_ns() - start

            response = datastream_pb2.DataResponse(
                request_id=request.request_id,
                result=result,
                status="SUCCESS",
                processing_time_ns=elapsed_ns,
                metadata={"processor": "unary"}
            )
            self.metrics.record_message_sent(len(result))
            return response

        except Exception as e:
            self.metrics.record_error()
            logger.error(f"Error processing request {request.request_id}: {e}")
            context.set_code(grpc.StatusCode.INTERNAL)
            context.set_details(str(e))
            return datastream_pb2.DataResponse(
                request_id=request.request_id,
                status="ERROR",
                processing_time_ns=time.perf_counter_ns() - start,
                metadata={"error": str(e)}
            )

    def StreamResults(self, request, context):
        """Server streaming RPC - process request and stream back results."""
        self.metrics.record_request()
        self.metrics.record_message_received(len(request.payload))
        logger.info(f"StreamResults started for request {request.request_id}")

        try:
            # Process data in chunks and stream results back
            payload = request.payload
            chunk_size = int(request.metadata.get("chunk_size", "4096"))
            offset = 0
            sequence = 0

            while offset < len(payload) and not context.is_active():
                break

            offset = 0
            while offset < len(payload):
                if not context.is_active():
                    logger.info(f"Client disconnected for request {request.request_id}")
                    return

                chunk = payload[offset:offset + chunk_size]
                start = time.perf_counter_ns()

                result = self.processor.process(
                    chunk,
                    request.data_type,
                    dict(request.metadata)
                )

                elapsed_ns = time.perf_counter_ns() - start

                response = datastream_pb2.DataResponse(
                    request_id=f"{request.request_id}-{sequence}",
                    result=result,
                    status="SUCCESS",
                    processing_time_ns=elapsed_ns,
                    metadata={
                        "sequence": str(sequence),
                        "offset": str(offset),
                        "chunk_size": str(len(chunk)),
                        "total_size": str(len(payload))
                    }
                )
                self.metrics.record_message_sent(len(result))
                yield response

                offset += chunk_size
                sequence += 1

            # Send final completion marker
            yield datastream_pb2.DataResponse(
                request_id=request.request_id,
                result=b"",
                status="COMPLETE",
                processing_time_ns=0,
                metadata={
                    "total_chunks": str(sequence),
                    "total_bytes_processed": str(len(payload))
                }
            )

        except Exception as e:
            self.metrics.record_error()
            logger.error(f"Error in StreamResults for {request.request_id}: {e}")
            context.set_code(grpc.StatusCode.INTERNAL)
