def create_server(
    port: int = 50051,
    max_workers: int = None,
    max_concurrent_rpcs: int = None,
):
    """Create and configure the gRPC server optimized for high throughput."""

    # Auto-detect optimal worker count
    if max_workers is None:
        import multiprocessing
        max_workers = max(multiprocessing.cpu_count() * 2, 8)

    logger.info(f"Configuring server with {max_workers} workers")

    # Server options optimized for high throughput and low latency
    # No message size limits, no rate limiting
    server_options = [
        # Remove message size limits entirely (-1 = unlimited)
        ("grpc.max_send_message_length", -1),
        ("grpc.max_receive_message_length", -1),
        # Large window sizes for flow control - allows more data in flight
        ("grpc.http2.initial_connection_window_size", 64 * 1024 * 1024),  # 64MB
        ("grpc.http2.initial_window_size", 64 * 1024 * 1024),  # 64MB
        # Increase max concurrent streams per connection
        ("grpc.max_concurrent_streams", 1000),
        # Keep-alive settings for long-lived connections
        ("grpc.keepalive_time_ms", 10000),
        ("grpc.keepalive_timeout_ms", 5000),
        ("grpc.keepalive_permit_without_calls", 1),
        ("grpc.http2.max_pings_without_data", 0),
        ("grpc.http2.min_time_between_pings_ms", 5000),
        ("grpc.http2.min_ping_interval_without_data_ms", 5000),
        # Large metadata limits
        ("grpc.max_metadata_size", 16 * 1024 * 1024),  # 16MB
        # Enable SO_REUSEPORT for better load distribution
        ("grpc.so_reuseport", 1),
        # Larger per-RPC buffer
        ("grpc.per_rpc_retry_buffer_size", 64 * 1024 * 1024),  # 64MB
    ]

    if max_concurrent_rpcs is not None:
        server_options.append(("grpc.max_concurrent_rpcs", max_concurrent_rpcs))

    # Create thread pool with optimal settings
    thread_pool = futures.ThreadPoolExecutor(
        max_workers=max_workers,
        thread_name_prefix="grpc-worker"
    )

    server = grpc.server(
        thread_pool,
        options=server_options,
        # No interceptors that could slow things down
        maximum_concurrent_rpcs=max_concurrent_rpcs,
    )

    # Register servicer
    servicer = DataStreamServicer()
    datastream_pb2_grpc.add_DataStreamServiceServicer_to_server(servicer, server)

    # Bind to port
    address = f"[::]:{port}"
    server.add_insecure_port(address)

    logger.info(f"Server configured on {address}")
    logger.info(f"Server options: workers={max_workers}, "
                f"max_concurrent_rpcs={max_concurrent_rpcs or 'unlimited'}")

    return server, servicer


def serve(port=50051, max_workers=None):
    """Start the gRPC server and block until shutdown."""
    server, servicer = create_server(port=port, max_workers=max_workers)

    # Graceful shutdown handling
    shutdown_event = futures.Future()

    def signal_handler(signum, frame):
        logger.info(f"Received signal {signum}, initiating graceful shutdown...")
        stats = servicer.metrics.get_stats()
        logger.info(f"Final metrics: {stats}")
        shutdown_event.set_result(True)

    signal.signal(signal.SIGINT, signal_handler)
    signal.signal(signal.SIGTERM, signal_handler)

    server.start()
    logger.info(f"Server started and listening on port {port}")
    logger.info("Ready to accept connections - no rate limiting, no message size limits")

    # Periodic stats logging
    def log_stats():
        while not shutdown_event.done():
            try:
                shutdown_event.result(timeout=30)
                break
            except futures.TimeoutError:
                stats = servicer.metrics.get_stats()
                logger.info(
                    f"Stats: requests={stats['total_requests']}, "
                    f"msgs_in={stats['total_messages_received']}, "
                    f"msgs_out={stats['total_messages_sent']}, "
                    f"bytes_in={stats['total_bytes_received']}, "
                    f"bytes_out={stats['total_bytes_sent']}, "
                    f"errors={stats['errors']}, "
                    f"rps={stats['avg_requests_per_second']:.1f}, "
                    f"uptime={stats['uptime_seconds']:.0f}s"
                )

    stats_thread = futures.ThreadPoolExecutor(max_workers=1)
    stats_thread.submit(log_stats)

    try:
        shutdown_event.result()
    except KeyboardInterrupt:
        pass
    finally:
        logger.info("Shutting down server (5s grace period)...")
        server.stop(grace=5).wait()
        stats_thread.shutdown(wait=False)
        logger.info("Server shut down complete")


