def run_example_client():
    """Example client demonstrating all RPC types."""
    import uuid

    # Client options matching server for optimal throughput
    channel_options = [
        ("grpc.max_send_message_length", -1),
        ("grpc.max_receive_message_length", -1),
        ("grpc.http2.initial_connection_window_size", 64 * 1024 * 1024),
        ("grpc.http2.initial_window_size", 64 * 1024 * 1024),
        ("grpc.max_concurrent_streams", 1000),
        ("grpc.keepalive_time_ms", 10000),
        ("grpc.keepalive_timeout_ms", 5000),
        ("grpc.keepalive_permit_without_calls", 1),
    ]

    channel = grpc.insecure_channel("localhost:50051", options=channel_options)
    stub = datastream_pb2_grpc.DataStreamServiceStub(channel)

    # 1. Health check
    logger.info("=== Health Check ===")
    health = stub.HealthCheck(datastream_pb2.HealthRequest(service_name="test"))
    logger.info(f"Health: status={health.status}, uptime={health.uptime_seconds}s, "
                f"processed={health.requests_processed}")

    # 2. Unary RPC
    logger.info("\n=== Unary RPC ===")
    request = datastream_pb2.DataRequest(
        request_id=str(uuid.uuid4()),
        payload=b"Hello, World!" * 100,
        data_type="hash",
        timestamp=int(time.time() * 1000),
        metadata={"source": "test_client"}
    )
    response = stub.ProcessData(request)
    logger.info(f"Unary response: status={response.status}, "
                f"processing_time={response.processing_time_ns / 1e6:.2f}ms, "
                f"result_size={len(response.result)}")

    # 3. Server streaming RPC
    logger.info("\n=== Server Streaming RPC ===")
    request = datastream_pb2.DataRequest(
        request_id=str(uuid.uuid4()),
        payload=b"X" * 16384,
        data_type="echo",
        timestamp=int(time.time() * 1000),
        metadata={"chunk_size": "4096"}
    )
    chunk_count = 0
    for response in stub.StreamResults(request):
        chunk_count += 1
        logger.info(f"  Chunk {chunk_count}: status={response.status}, "
                    f"result_size={len(response.result)}")
    logger.info(f"  Total chunks received: {chunk_count}")

    # 4. Client streaming RPC
    logger.info("\n=== Client Streaming RPC ===")

    def generate_requests(count=10):
        for i in range(count):
            yield datastream_pb2.DataRequest(
                request_id=f"stream-{i}",
                payload=f"message-{i}-{'data' * 100}".encode(),
                data_type="echo",
                timestamp=int(time.time() * 1000),
                metadata={"sequence": str(i)}
            )

    response = stub.IngestStream(generate_requests(10))
    logger.info(f"IngestStream response: status={response.status}, "
                f"result_size={len(response.result)}, "
                f"messages={response.metadata.get('total_messages')}")

    # 5. Bidirectional streaming RPC
    logger.info("\n=== Bidirectional Streaming RPC ===")

    def generate_bidi_requests(count=5):
        for i in range(count):
            yield datastream_pb2.DataRequest(
                request_id=f"bidi-{i}",
                payload=f"bidi-data-{i}".encode() * 50,
                data_type="hash",
                timestamp=int(time.time() * 1000),
                metadata={"sequence": str(i)}
            )

    msg_count = 0
    for response in stub.BidirectionalStream(generate_bidi_requests(5)):
        msg_count += 1
        logger.info(f"  Bidi response {msg_count}: id={response.request_id}, "
                    f"status={response.status}, "
                    f"time={response.processing_time_ns / 1e6:.2f}ms")

    # 6. Throughput test
    logger.info("\n=== Throughput Test (1000 unary requests) ===")
    start = time.perf_counter()
    num_requests = 1000

    for i in range(num_requests):
        request = datastream_pb2.DataRequest(
            request_id=str(i),
            payload=b"benchmark" * 100,
            data_type="echo",
            timestamp=int(time.time() * 1000),
        )
        stub.ProcessData(request)

    elapsed = time.perf_counter() - start
    logger.info(f"Completed {num_requests} requests in {elapsed:.2f}s "
                f"({num_requests / elapsed:.0f} req/s)")

    # Final health check
    health = stub.HealthCheck(datastream_pb2.HealthRequest(service_name="test"))
    logger.info(f"\nFinal health: processed={health.requests_processed}")

    channel.close()


